              >
                Cancel
              </button>
              <button
                onClick={handleDeleteAccount}
                disabled={deleteLoading}
                className="bg-red-500 hover:bg-red-600 disabled:opacity-60 text-white font-bold text-sm py-2 px-4 rounded-lg transition-colors flex items-center gap-2"
