"use client";

import { useState } from 'react';
import { Calculator, CheckCircle2, ChevronRight, Award, GraduationCap, Briefcase, Languages, RefreshCcw } from 'lucide-react';

export default function VisaCalculator() {
  const [points, setPoints] = useState(0);
  const [calculated, setCalculated] = useState(false);

  // Simple state for the form
  const [form, setForm] = useState({
    salary: '0',
    education: '0',
    experience: '0',
    hsk: '0',
    age: '0'
  });

  const calculateScore = () => {
    // For demo purposes, we just sum up simplistic string values casted to integers
    // In reality, this requires the complex Chinese Z-Visa A/B/C tier calculation logic
    let total = 0;
    Object.values(form).forEach(val => total += parseInt(val, 10));
    setPoints(total);
    setCalculated(true);
  };

  const getTier = () => {
    if (points >= 85) return { tier: 'Class A (Top Talent)', color: 'text-emerald-600', bg: 'bg-emerald-50 border-emerald-200', desc: 'Highly sought after. Green channel processing.' };
    if (points >= 60) return { tier: 'Class B (Professional)', color: 'text-indigo-600', bg: 'bg-indigo-50 border-indigo-200', desc: 'Standard work permit. Most expats fall here.' };
    return { tier: 'Class C (Temporary)', color: 'text-amber-600', bg: 'bg-amber-50 border-amber-200', desc: 'Restricted quotas. Needs special justification.' };
  };

  return (
    <div className="min-h-screen bg-slate-50 py-12 font-sans">
      <div className="max-w-4xl mx-auto px-4 space-y-10">
        
        {/* Header */}
        <div className="text-center space-y-4">
          <div className="w-16 h-16 bg-white border border-slate-200 rounded-2xl flex items-center justify-center mx-auto shadow-sm text-indigo-600">
            <Calculator size={32} />
          </div>
          <h1 className="text-4xl font-extrabold text-slate-900 tracking-tight">
            Z-Visa Points Calculator
          </h1>
          <p className="text-lg text-slate-500 max-w-xl mx-auto">
            China uses a points-based system to classify foreign workers into A, B, and C tiers. Find out if you meet the 60-point threshold for a standard Z-Visa.
          </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-5 gap-8">
          
          {/* Form Side */}
          <div className="md:col-span-3 space-y-6 bg-white p-8 rounded-2xl border border-slate-200 shadow-sm">
            
            {/* Education */}
            <div className="space-y-3">
              <label className="flex items-center gap-2 font-bold text-slate-800">
                <GraduationCap size={18} className="text-slate-400" />
                Highest Degree
              </label>
              <select 
                className="w-full p-3 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-slate-700 bg-slate-50"
                value={form.education}
                onChange={(e) => setForm({...form, education: e.target.value})}
              >
                <option value="0">Select Degree...</option>
                <option value="10">Bachelor's Degree (10 pts)</option>
                <option value="15">Master's Degree (15 pts)</option>
                <option value="20">Ph.D. or higher (20 pts)</option>
              </select>
            </div>

            {/* Salary */}
            <div className="space-y-3">
              <label className="flex items-center gap-2 font-bold text-slate-800">
                <Award size={18} className="text-slate-400" />
                Annual Salary (RMB)
              </label>
              <select 
                className="w-full p-3 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-slate-700 bg-slate-50"
                value={form.salary}
                onChange={(e) => setForm({...form, salary: e.target.value})}
              >
                <option value="0">Select Range...</option>
                <option value="5">50k - 70k (5 pts)</option>
                <option value="10">70k - 100k (10 pts)</option>
                <option value="15">100k - 150k (15 pts)</option>
                <option value="20">150k+ (20 pts)</option>
              </select>
            </div>

            {/* Experience */}
            <div className="space-y-3">
              <label className="flex items-center gap-2 font-bold text-slate-800">
                <Briefcase size={18} className="text-slate-400" />
                Related Work Experience
              </label>
              <select 
                className="w-full p-3 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-slate-700 bg-slate-50"
                value={form.experience}
                onChange={(e) => setForm({...form, experience: e.target.value})}
              >
                <option value="0">Select Experience...</option>
                <option value="0">None / Fresh Grad (0 pts)</option>
                <option value="5">2 Years (5 pts)</option>
                <option value="10">3-4 Years (10 pts)</option>
                <option value="15">5+ Years (15 pts)</option>
              </select>
            </div>

            {/* HSK */}
            <div className="space-y-3">
              <label className="flex items-center gap-2 font-bold text-slate-800">
                <Languages size={18} className="text-slate-400" />
                Chinese Proficiency (HSK)
              </label>
              <select 
                className="w-full p-3 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-slate-700 bg-slate-50"
                value={form.hsk}
                onChange={(e) => setForm({...form, hsk: e.target.value})}
              >
                <option value="0">Select Level...</option>
                <option value="0">None / HSK 1-2 (0 pts)</option>
                <option value="2">HSK 3 (2 pts)</option>
                <option value="4">HSK 4 (4 pts)</option>
                <option value="5">HSK 5+ (5 pts)</option>
              </select>
            </div>

            <button 
              onClick={calculateScore}
              className="w-full bg-slate-900 text-white font-bold py-4 rounded-xl hover:bg-slate-800 transition-colors mt-4 shadow-sm"
            >
              Calculate My Score
            </button>
          </div>

          {/* Results Side */}
          <div className="md:col-span-2 space-y-6">
            {!calculated ? (
              <div className="h-full bg-slate-200 border border-slate-300 border-dashed rounded-2xl flex flex-col items-center justify-center text-center p-8 text-slate-500">
                <CheckCircle2 size={48} className="mb-4 opacity-50" />
                <p className="font-medium">Fill out the basic criteria to see your eligibility tier.</p>
              </div>
            ) : (
              <div className={`p-8 rounded-2xl border flex flex-col items-center text-center animate-in zoom-in-95 duration-500 ${getTier().bg}`}>
                <div className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-2">Your Score</div>
                <div className={`text-7xl font-black mb-4 ${getTier().color}`}>
                  {points}
                </div>
                <div className={`text-xl font-bold mb-2 ${getTier().color}`}>
                  {getTier().tier}
                </div>
                <p className="text-sm text-slate-600 mb-6">
                  {getTier().desc}
                </p>

                <div className="w-full bg-white rounded-xl p-4 border border-opacity-50 text-left space-y-3 shadow-sm">
                  <div className="flex justify-between items-center text-sm">
                    <span className="font-medium text-slate-600">Threshold (Class B)</span>
                    <span className="font-bold text-slate-900">60 points</span>
                  </div>
                  <div className="w-full bg-slate-100 rounded-full h-2">
                    <div 
                      className={`h-2 rounded-full ${points >= 60 ? 'bg-emerald-500' : 'bg-red-500'}`} 
                      style={{ width: `${Math.min(100, (points / 60) * 100)}%` }}
                    ></div>
                  </div>
                </div>

                <button 
                  onClick={() => { setCalculated(false); setPoints(0); }}
                  className="mt-8 flex items-center gap-2 text-sm font-bold text-slate-500 hover:text-slate-800 transition-colors"
                >
                  <RefreshCcw size={16} />
                  Recalculate
                </button>
              </div>
            )}
          </div>

        </div>
      </div>
    </div>
  );
}

"use client";

import React, { useEffect, useRef } from 'react';
import { ArrowLeft, ArrowRight, CheckCircle, GraduationCap, MapPin, DollarSign, Lock, ShieldCheck, MessageSquare, AlertTriangle, Sparkles, LogIn } from 'lucide-react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { unlockSchema } from '@/lib/schema';
import { submitLead } from '@/app/actions/leads';
import { toast } from 'sonner';
import { siteConfig } from '@/config/site';
import Link from 'next/link';
import { useAuth } from '@/components/providers/AuthProvider';
import { createClient } from '@/lib/supabase/client';

export default function UnlockResults({ step, setStep, formData, matchResults, matchError }) {
  const { register, handleSubmit, formState: { errors, isSubmitting } } = useForm({
    resolver: zodResolver(unlockSchema)
  });
  const { user } = useAuth();
  const supabase = createClient();
  const hasSavedRef = useRef(false);

  // Auto-unlock for logged-in users and save match results
  useEffect(() => {
    if (user && matchResults && step !== 'unlocked') {
      setStep('unlocked');
    }
  }, [user, matchResults, step]);

  // Auto-save match results for verified logged-in users (once)
  useEffect(() => {
    if (user && matchResults && !hasSavedRef.current) {
      hasSavedRef.current = true;
      supabase.from('match_history').insert({
        user_id: user.id,
        form_data: formData,
        results: matchResults,
      }).then(({ error }) => {
        if (!error) {
          toast.success('Match results saved to your history!', { duration: 3000 });
        }
      });
    }
  }, [user, matchResults]);

  const onUnlock = async (data) => {
    try {
      const result = await submitLead(data.email);
      if (result.success) {
        toast.success("Successfully unlocked!");
        setStep('unlocked');
      } else {
        toast.error(result.error || "Failed to unlock.");
      }
    } catch (e) {
      toast.error("Something went wrong!");
    }
  };

  const isUnlocked = step === 'unlocked';
  const unis = matchResults?.universities || [];
  const topMatch = unis[0];
  const cscProb = matchResults?.cscProbability || 0;

  // Error state
  if (matchError && !matchResults) {
    return (
      <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
        <div className="flex justify-start">
          <button 
            onClick={() => setStep('home')}
            className="flex items-center gap-2 text-sm font-bold text-slate-500 hover:text-slate-900 transition-colors bg-white px-4 py-2 rounded-lg shadow-sm border border-slate-200"
          >
            <ArrowLeft size={16} /> Try Again
          </button>
        </div>
        <div className="text-center space-y-4 py-12">
          <AlertTriangle className="w-12 h-12 text-amber-500 mx-auto" />
          <h2 className="text-2xl font-bold text-slate-900 font-heading">AI Matching Unavailable</h2>
          <p className="text-slate-500 max-w-md mx-auto">
            Our AI engine is temporarily busy. Please try again in a moment, or use our{' '}
            <Link href="/tools#advisor" className="text-emerald-600 hover:underline font-bold">AI Study Advisor</Link> for personalized guidance.
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">

      {/* Back Button */}
      <div className="flex justify-start">
        <button 
          onClick={() => setStep('home')}
          className="flex items-center gap-2 text-sm font-bold text-slate-500 hover:text-slate-900 transition-colors bg-white px-4 py-2 rounded-lg shadow-sm border border-slate-200"
        >
          <ArrowLeft size={16} /> Back to Search
        </button>
      </div>

      <div className="text-center space-y-2">
        <span className="bg-emerald-100 text-emerald-800 text-sm font-bold px-3 py-1 rounded-full">Analysis Complete</span>
        <h2 className="text-3xl font-extrabold text-slate-900 font-heading">
          {topMatch ? `We found your ${topMatch.matchPercent}% Match!` : 'Your AI Results'}
        </h2>
        <p className="text-slate-500">Based on your {formData.nationality} nationality and {formData.gpa?.value} GPA.</p>
      </div>

      {/* Top University Match Card */}
      {topMatch && (
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden relative">
          <div className="p-6 md:p-8 border-b border-slate-100">
            <div className="flex justify-between items-start mb-4">
              <div>
                <h3 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
                  {topMatch.name} ({topMatch.code}) <ShieldCheck className="text-blue-500" size={24} />
                </h3>
                <p className="text-slate-500 font-medium">{topMatch.tier} 鈥?CSC Agency: {topMatch.cscAgency}</p>
              </div>
              <div className="bg-green-100 text-green-700 px-3 py-1 rounded-lg font-bold text-sm border border-green-200">
                {topMatch.matchPercent}% Match
              </div>
            </div>

            <div className="grid grid-cols-2 md:grid-cols-3 gap-4 mt-6">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-slate-100 rounded-lg text-slate-600"><GraduationCap size={20} /></div>
                <div>
                  <p className="text-xs text-slate-500 uppercase font-bold">Program</p>
                  <p className="font-semibold">{topMatch.program}</p>
                </div>
              </div>
              <div className="flex items-center gap-3">
                <div className="p-2 bg-slate-100 rounded-lg text-slate-600"><MapPin size={20} /></div>
                <div>
                  <p className="text-xs text-slate-500 uppercase font-bold">Location</p>
                  <p className="font-semibold">{topMatch.city}</p>
                </div>
              </div>
              <div className="flex items-center gap-3">
                <div className="p-2 bg-slate-100 rounded-lg text-slate-600"><DollarSign size={20} /></div>
                <div>
                  <p className="text-xs text-slate-500 uppercase font-bold">Tuition / Year</p>
                  <p className="font-semibold">~ ${topMatch.tuitionUSD?.toLocaleString()} USD</p>
                </div>
              </div>
            </div>

            {/* Why Match */}
            <div className="mt-4 p-3 bg-emerald-50 rounded-xl border border-emerald-100 text-sm text-emerald-800">
              <strong>Why this match:</strong> {topMatch.whyMatch}
            </div>
          </div>

          {/* Locked Area */}
          <div className="relative">
            {!isUnlocked && (
              <div className="absolute inset-0 z-10 backdrop-blur-md bg-white/60 flex flex-col items-center justify-center p-6 text-center border-t border-slate-100">
                <div className="bg-white p-6 rounded-2xl shadow-xl border border-slate-100 max-w-md w-full animate-in zoom-in-95">
                  {/* Logged-out: show sign-in prompt first, then email gate as fallback */}
                  {!user ? (
                    <>
                      <Lock className="w-12 h-12 text-emerald-500 mx-auto mb-4" />
                      <h3 className="text-xl font-bold mb-2">Unlock the Full Report</h3>
                      <p className="text-sm text-slate-500 mb-4">
                        Sign in to instantly unlock your full report, save your match results, and access all features.
                      </p>
                      <Link
                        href="/auth/login?redirect=/"
                        className="w-full bg-emerald-500 hover:bg-emerald-600 text-white font-bold py-3 rounded-lg transition-all shadow-lg hover:shadow-emerald-500/20 hover:-translate-y-0.5 flex items-center justify-center gap-2 mb-4"
                      >
                        <LogIn size={16} />
                        Sign In to Unlock
                      </Link>
                      <div className="relative">
                        <div className="absolute inset-0 flex items-center">
                          <div className="w-full border-t border-slate-200"></div>
                        </div>
                        <div className="relative flex justify-center text-xs">
                          <span className="bg-white px-2 text-slate-400">or unlock with email</span>
                        </div>
                      </div>
                      <form onSubmit={handleSubmit(onUnlock)} className="space-y-3 mt-4">
                        <div>
                          <input 
                            type="email" 
                            placeholder="Your email address" 
                            {...register('email')}
                            className={`w-full p-3 bg-slate-50 border ${errors.email ? 'border-red-500' : 'border-slate-200'} rounded-lg focus:ring-2 focus:ring-emerald-500 outline-none`}
                          />
                          {errors.email && <p className="text-xs text-red-500 text-left mt-1">{errors.email.message}</p>}
                        </div>

                        <label className="flex items-start gap-2 text-left cursor-pointer group pb-2 relative">
                          <input 
                            type="checkbox" 
                            {...register('agreeTerms')}
                            className="mt-0.5 w-4 h-4 rounded border-slate-300 text-emerald-500 focus:ring-emerald-500 cursor-pointer" 
                          />
                          <span className="text-[11px] text-slate-500 leading-tight">
                            I agree to the <Link href="/terms" target="_blank" className="text-emerald-600 hover:underline">Terms of Service</Link> & <Link href="/privacy" target="_blank" className="text-emerald-600 hover:underline">Privacy Policy</Link>.
                          </span>
                        </label>
